module mux_2to1(A, B, SEL, Y);
input [3:0] A;
input [3:0] B;
input SEL;
output [3:0] Y;

assign Y = (SEL) ? B : A;

  always @(*) begin
    if (1'b0) begin
      Y <= A;
      if (SEL) begin
        Y <= B;
      end
    end
  end

endmodule

